SELECT o.*
FROM `order` o
WHERE o.member_id = #{memberId}
  AND o.view_status = '0'

    AND o.status = #{status}

ORDER BY o.create_time DESC

SELECT o.*
FROM `order` o
WHERE o.id = #{id}
  AND o.member_id = #{memberId}
  AND o.view_status = '0'
LIMIT 1

mapper.update:
UPDATE `order`
SET status = 1,
    payment_status = 2,
    update_time = #{now},
    update_by = #{memberId}
WHERE id = #{id}
  AND member_id = #{memberId}
  AND view_status = '0'
  AND status = 0
  AND payment_status = 1

UPDATE `order`
SET status = 4,
    payment_status = 3,
    reason = #{reason},
    update_time = #{now},
    update_by = #{memberId}
WHERE id = #{id}
  AND member_id = #{memberId}
  AND view_status = '0'
  AND status = 0

UPDATE `order`
SET view_status = '1',
    update_time = #{now},
    update_by = #{memberId}
WHERE id = #{id}
  AND member_id = #{memberId}
  AND view_status = '0'
  AND status NOT IN (0, 1)

UPDATE `order`
SET status = 5,
    is_refund = 'YES',
    refund = amount,
    update_time = #{now}
WHERE id = #{id}
